import{c as t,Q as o,j as a,m as r}from"./chunks/framework.B--3jHRd.js";const d=JSON.parse('{"title":"What is AetherLake?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),i={name:"guide/introduction.md"};function n(s,e,l,c,g,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="what-is-aetherlake" tabindex="-1">What is AetherLake? <a class="header-anchor" href="#what-is-aetherlake" aria-label="Permalink to &quot;What is AetherLake?&quot;">​</a></h1><p>AetherLake is a <strong>batteries-included, Kubernetes-native Data Lakehouse</strong> that brings together best-in-class open-source tools into a single, cohesive platform. Instead of spending weeks gluing together storage, compute, catalog, orchestration, and security layers — deploy everything in minutes.</p><h2 id="key-principles" tabindex="-1">Key principles <a class="header-anchor" href="#key-principles" aria-label="Permalink to &quot;Key principles&quot;">​</a></h2><ul><li>🏗️ <strong>Modular</strong> — Enable or disable any component via a single toggle</li><li>🔐 <strong>Secure by default</strong> — Centralized SSO with Keycloak, RBAC across all services</li><li>📦 <strong>Cloud-native</strong> — Helm charts, Kubernetes operators, and S3-compatible storage</li><li>🎛️ <strong>Unified control</strong> — Web-based Control Panel to manage the entire platform</li><li>🌐 <strong>Multi-language</strong> — Control Panel supports English and Turkish (extensible)</li></ul><h2 id="core-technologies" tabindex="-1">Core Technologies <a class="header-anchor" href="#core-technologies" aria-label="Permalink to &quot;Core Technologies&quot;">​</a></h2><p>AetherLake integrates several major open-source projects:</p><ul><li><strong>Storage:</strong> MinIO (S3 compatible)</li><li><strong>Table Format:</strong> Apache Iceberg</li><li><strong>Catalog:</strong> Apache Polaris (REST Catalog)</li><li><strong>Compute:</strong> Trino &amp; Apache Spark</li><li><strong>Vector DB:</strong> Milvus</li><li><strong>Orchestration:</strong> Apache Airflow</li><li><strong>Identity:</strong> Keycloak</li></ul>',7)])])}const u=t(i,[["render",n]]);export{d as __pageData,u as default};
